{
  "name": "Gemini Strike: Hand Commander",
  "description": "An immersive augmented reality shooting game where you use hand gestures to battle digital invaders. Powered by Gemini for tactical briefings and MediaPipe for real-time hand tracking.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Vector2 {
  x: number;
  y: number;
}

export interface Target {
  id: string;
  pos: Vector2;
  vel: Vector2;
  size: number;
  health: number;
  maxHealth: number;
  type: 'drone' | 'scout' | 'boss';
  color: string;
  points: number;
}

export interface Particle {
  id: string;
  pos: Vector2;
  vel: Vector2;
  life: number;
  maxLife: number;
  color: string;
}

export interface GameState {
  score: number;
  health: number;
  level: number;
  isGameOver: boolean;
  isPlaying: boolean;
  targets: Target[];
  particles: Particle[];
  handActive: boolean;
  handPos: Vector2;
  isFiring: boolean;
  lastFired: number;
  briefing: string;
}

export interface MediaPipeLandmark {
  x: number;
  y: number;
  z: number;
}

export const GAME_CONFIG = {
  CANVAS_WIDTH: 1280,
  CANVAS_HEIGHT: 720,
  INITIAL_HEALTH: 100,
  TARGET_SPAWN_RATE: 1500, // ms
  FIRE_RATE: 150, // ms
  TARGET_BASE_SPEED: 1.5,
  PARTICLE_COUNT: 12,
  HAND_SMOOTHING: 0.6,
};

export const COLORS = {
  CYAN: '#22d3ee',
  MAGENTA: '#d946ef',
  YELLOW: '#eab308',
  RED: '#ef4444',
  GREEN: '#22c55e',
  SLATE_900: '#0f172a',
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getTacticalBriefing = async (level: number): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a futuristic AI tactical commander. Give a short, 2-sentence mission briefing for Level ${level} of a space shooter. The player uses hand gestures to shoot digital drones. Make it sound urgent and high-tech.`,
      config: {
        temperature: 0.8,
        topP: 0.9,
      },
    });
    return response.text || "Commander, standard protocol active. Eliminate all digital anomalies.";
  } catch (error) {
    console.error("Gemini Briefing Error:", error);
    return "Tactical data stream interrupted. Proceed with caution.";
  }
};

export const getTauntOrPraise = async (isVictory: boolean, score: number): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a futuristic tactical commander. Give a 1-sentence ${isVictory ? 'praise' : 'encouragement'} based on a score of ${score} in an AR hand-tracking game.`,
      config: {
        temperature: 1.0,
      },
    });
    return response.text || "Systems nominal.";
  } catch (error) {
    return isVictory ? "Outstanding performance." : "Recalibrating for next mission.";
  }
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GameState, Target, Particle, Vector2 } from './types';
import { GAME_CONFIG, COLORS } from './constants';
import { getTacticalBriefing } from './services/geminiService';
import HUD from './components/HUD';
import GameEngine from './components/GameEngine';
import SplashScreen from './components/SplashScreen';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    score: 0,
    health: GAME_CONFIG.INITIAL_HEALTH,
    level: 1,
    isGameOver: false,
    isPlaying: false,
    targets: [],
    particles: [],
    handActive: false,
    handPos: { x: 0.5, y: 0.5 },
    isFiring: false,
    lastFired: 0,
    briefing: 'Awaiting Tactical Link...',
  });

  const [isLoading, setIsLoading] = useState(false);

  const startGame = async () => {
    setIsLoading(true);
    const briefing = await getTacticalBriefing(1);
    setGameState(prev => ({
      ...prev,
      isPlaying: true,
      isGameOver: false,
      score: 0,
      health: GAME_CONFIG.INITIAL_HEALTH,
      level: 1,
      briefing,
      targets: [],
      particles: [],
    }));
    setIsLoading(false);
  };

  const handleGameOver = () => {
    setGameState(prev => ({ ...prev, isGameOver: true, isPlaying: false }));
  };

  const updateGameState = useCallback((updates: Partial<GameState>) => {
    setGameState(prev => ({ ...prev, ...updates }));
  }, []);

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-slate-950 font-rajdhani select-none">
      {!gameState.isPlaying && (
        <SplashScreen 
          onStart={startGame} 
          isLoading={isLoading} 
          isGameOver={gameState.isGameOver}
          score={gameState.score}
        />
      )}

      {gameState.isPlaying && (
        <>
          <HUD 
            score={gameState.score} 
            health={gameState.health} 
            level={gameState.level} 
            briefing={gameState.briefing}
            handActive={gameState.handActive}
          />

          <div className="absolute inset-0 z-0">
             <GameEngine 
                gameState={gameState}
                updateGameState={updateGameState}
                onGameOver={handleGameOver}
             />
          </div>

          <div className="absolute inset-0 pointer-events-none border-[12px] border-cyan-500/20 box-border z-20">
            <div className="absolute top-4 left-4 w-12 h-12 border-t-2 border-l-2 border-cyan-400"></div>
            <div className="absolute top-4 right-4 w-12 h-12 border-t-2 border-r-2 border-cyan-400"></div>
            <div className="absolute bottom-4 left-4 w-12 h-12 border-b-2 border-l-2 border-cyan-400"></div>
            <div className="absolute bottom-4 right-4 w-12 h-12 border-b-2 border-r-2 border-cyan-400"></div>
          </div>

          <div className="scanner-line"></div>
        </>
      )}
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { GameState, Target, Particle, Vector2, MediaPipeLandmark } from '../types';
import { GAME_CONFIG, COLORS } from '../constants';

interface GameEngineProps {
  gameState: GameState;
  updateGameState: (updates: Partial<GameState>) => void;
  onGameOver: () => void;
}

const GameEngine: React.FC<GameEngineProps> = ({ gameState, updateGameState, onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const lastUpdateRef = useRef<number>(0);
  const lastSpawnRef = useRef<number>(0);
  const handsRef = useRef<any>(null);
  const smoothedHandPos = useRef<Vector2>({ x: 0.5, y: 0.5 });

  // Local state references for the game loop to avoid stale closure issues
  const targetsRef = useRef<Target[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const healthRef = useRef<number>(GAME_CONFIG.INITIAL_HEALTH);
  const scoreRef = useRef<number>(0);
  const isFiringRef = useRef<boolean>(false);
  const lastFiredRef = useRef<number>(0);

  // Initialize MediaPipe
  useEffect(() => {
    if (!videoRef.current) return;

    // Access the global variable defined in index.html scripts
    const { Hands, Camera } = (window as any);

    if (!Hands || !Camera) {
      console.error("MediaPipe Hands not loaded yet");
      return;
    }

    const hands = new Hands({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/hands/${file}`
    });

    hands.setOptions({
      maxNumHands: 1,
      modelComplexity: 1,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5
    });

    hands.onResults((results: any) => {
      if (results.multiHandLandmarks && results.multiHandLandmarks.length > 0) {
        const landmarks = results.multiHandLandmarks[0];

        // Use Index Finger Tip (8) for position
        const indexTip = landmarks[8];
        const thumbTip = landmarks[4];

        // Smoothed position tracking (inverted X for mirror effect)
        const targetX = 1 - indexTip.x;
        const targetY = indexTip.y;

        smoothedHandPos.current = {
          x: smoothedHandPos.current.x * GAME_CONFIG.HAND_SMOOTHING + targetX * (1 - GAME_CONFIG.HAND_SMOOTHING),
          y: smoothedHandPos.current.y * GAME_CONFIG.HAND_SMOOTHING + targetY * (1 - GAME_CONFIG.HAND_SMOOTHING)
        };

        // Detect "firing" gesture - distance between thumb and index finger
        const distance = Math.sqrt(
          Math.pow(indexTip.x - thumbTip.x, 2) + 
          Math.pow(indexTip.y - thumbTip.y, 2)
        );

        // Pinch gesture detection
        const isPinching = distance < 0.05;

        updateGameState({
          handActive: true,
          handPos: smoothedHandPos.current,
          isFiring: isPinching
        });
        isFiringRef.current = isPinching;

      } else {
        updateGameState({ handActive: false, isFiring: false });
        isFiringRef.current = false;
      }
    });

    const camera = new Camera(videoRef.current, {
      onFrame: async () => {
        await hands.send({ image: videoRef.current! });
      },
      width: 1280,
      height: 720
    });

    camera.start();
    handsRef.current = hands;

    return () => {
      camera.stop();
      hands.close();
    };
  }, [updateGameState]);

  // Game loop
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const animate = (time: number) => {
      if (!gameState.isPlaying) return;

      const delta = lastUpdateRef.current ? time - lastUpdateRef.current : 0;
      lastUpdateRef.current = time;

      // 1. Spawning
      if (time - lastSpawnRef.current > (GAME_CONFIG.TARGET_SPAWN_RATE / (1 + (gameState.level - 1) * 0.2))) {
        const id = Math.random().toString(36).substr(2, 9);
        const type = Math.random() > 0.9 ? 'boss' : (Math.random() > 0.7 ? 'scout' : 'drone');
        const size = type === 'boss' ? 80 : (type === 'scout' ? 30 : 50);
        const health = type === 'boss' ? 5 : 1;

        targetsRef.current.push({
          id,
          pos: { x: Math.random() * (canvas.width - 100) + 50, y: -50 },
          vel: { x: (Math.random() - 0.5) * 2, y: GAME_CONFIG.TARGET_BASE_SPEED + Math.random() * gameState.level },
          size,
          health,
          maxHealth: health,
          type,
          color: type === 'boss' ? COLORS.MAGENTA : (type === 'scout' ? COLORS.YELLOW : COLORS.CYAN),
          points: type === 'boss' ? 500 : (type === 'scout' ? 200 : 100)
        });
        lastSpawnRef.current = time;
      }

      // 2. Firing Logic
      if (isFiringRef.current && time - lastFiredRef.current > GAME_CONFIG.FIRE_RATE) {
        lastFiredRef.current = time;
        const fireX = smoothedHandPos.current.x * canvas.width;
        const fireY = smoothedHandPos.current.y * canvas.height;

        // Hit Detection
        targetsRef.current = targetsRef.current.filter(t => {
          const dx = fireX - t.pos.x;
          const dy = fireY - t.pos.y;
          const dist = Math.sqrt(dx*dx + dy*dy);

          if (dist < t.size) {
            t.health -= 1;
            // Spawn impact particles
            for(let i=0; i<5; i++) {
              particlesRef.current.push({
                id: Math.random().toString(),
                pos: { x: fireX, y: fireY },
                vel: { x: (Math.random()-0.5)*10, y: (Math.random()-0.5)*10 },
                life: 1,
                maxLife: 1,
                color: t.color
              });
            }

            if (t.health <= 0) {
              scoreRef.current += t.points;
              // Level up logic
              if (scoreRef.current > gameState.level * 2000) {
                 updateGameState({ level: gameState.level + 1 });
              }
              // Spawn death particles
              for(let i=0; i<GAME_CONFIG.PARTICLE_COUNT; i++) {
                particlesRef.current.push({
                  id: Math.random().toString(),
                  pos: { ...t.pos },
                  vel: { x: (Math.random()-0.5)*15, y: (Math.random()-0.5)*15 },
                  life: 1,
                  maxLife: 1,
                  color: t.color
                });
              }
              return false;
            }
          }
          return true;
        });

        updateGameState({ score: scoreRef.current });
      }

      // 3. Movement & Collision
      targetsRef.current = targetsRef.current.filter(t => {
        t.pos.x += t.vel.x;
        t.pos.y += t.vel.y;

        // Bounce off walls
        if (t.pos.x < t.size || t.pos.x > canvas.width - t.size) t.vel.x *= -1;

        // Missed target penalty
        if (t.pos.y > canvas.height + t.size) {
          healthRef.current -= 10;
          updateGameState({ health: healthRef.current });
          if (healthRef.current <= 0) onGameOver();
          return false;
        }
        return true;
      });

      // Particles
      particlesRef.current = particlesRef.current.filter(p => {
        p.pos.x += p.vel.x;
        p.pos.y += p.vel.y;
        p.life -= 0.02;
        return p.life > 0;
      });

      // 4. Rendering
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Render Targets
      targetsRef.current.forEach(t => {
        ctx.save();
        ctx.translate(t.pos.x, t.pos.y);

        // Draw glow
        ctx.shadowBlur = 15;
        ctx.shadowColor = t.color;

        ctx.strokeStyle = t.color;
        ctx.lineWidth = 3;

        if (t.type === 'drone') {
          ctx.strokeRect(-t.size/2, -t.size/2, t.size, t.size);
          ctx.beginPath();
          ctx.moveTo(-t.size/4, -t.size/4);
          ctx.lineTo(t.size/4, t.size/4);
          ctx.stroke();
        } else if (t.type === 'scout') {
          ctx.beginPath();
          ctx.moveTo(0, -t.size/2);
          ctx.lineTo(t.size/2, t.size/2);
          ctx.lineTo(-t.size/2, t.size/2);
          ctx.closePath();
          ctx.stroke();
        } else {
          // Boss
          ctx.strokeRect(-t.size/2, -t.size/2, t.size, t.size);
          ctx.strokeRect(-t.size/3, -t.size/3, t.size*0.6, t.size*0.6);
        }

        // Health bar for boss
        if (t.maxHealth > 1) {
          ctx.fillStyle = COLORS.RED;
          ctx.fillRect(-t.size/2, -t.size/2 - 10, t.size, 5);
          ctx.fillStyle = COLORS.GREEN;
          ctx.fillRect(-t.size/2, -t.size/2 - 10, t.size * (t.health/t.maxHealth), 5);
        }

        ctx.restore();
      });

      // Render Particles
      particlesRef.current.forEach(p => {
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.fillRect(p.pos.x, p.pos.y, 4, 4);
      });
      ctx.globalAlpha = 1.0;

      // Render Crosshair
      const hx = smoothedHandPos.current.x * canvas.width;
      const hy = smoothedHandPos.current.y * canvas.height;

      ctx.save();
      ctx.translate(hx, hy);
      ctx.strokeStyle = isFiringRef.current ? COLORS.RED : COLORS.CYAN;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.arc(0, 0, isFiringRef.current ? 15 : 25, 0, Math.PI * 2);
      ctx.stroke();

      // Crosshair lines
      ctx.beginPath();
      ctx.moveTo(-35, 0); ctx.lineTo(-15, 0);
      ctx.moveTo(35, 0); ctx.lineTo(15, 0);
      ctx.moveTo(0, -35); ctx.lineTo(0, -15);
      ctx.moveTo(0, 35); ctx.lineTo(0, 15);
      ctx.stroke();

      if (isFiringRef.current) {
        ctx.fillStyle = COLORS.RED;
        ctx.beginPath();
        ctx.arc(0, 0, 5, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.restore();

      requestAnimationFrame(animate);
    };

    const requestId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(requestId);
  }, [gameState.isPlaying, gameState.level, onGameOver, updateGameState]);

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      {/* Hidden camera feed used for hand tracking */}
      <video
        ref={videoRef}
        className="hidden"
        playsInline
        muted
      />

      {/* Visible background camera feed (blurred and dimmed) */}
      <video
        className="absolute inset-0 w-full h-full object-cover scale-x-[-1] opacity-40 blur-sm brightness-50"
        autoPlay
        playsInline
        muted
        ref={(el) => {
           if (el && videoRef.current) {
             el.srcObject = videoRef.current.srcObject;
           }
        }}
      />

      <canvas
        ref={canvasRef}
        width={1280}
        height={720}
        className="relative w-full h-full object-contain"
      />
    </div>
  );
};

export default GameEngine;

import React from 'react';

interface HUDProps {
  score: number;
  health: number;
  level: number;
  briefing: string;
  handActive: boolean;
}

const HUD: React.FC<HUDProps> = ({ score, health, level, briefing, handActive }) => {
  return (
    <div className="absolute inset-0 pointer-events-none z-30 p-8 flex flex-col justify-between">
      {/* Top Bar */}
      <div className="flex justify-between items-start">
        <div className="bg-slate-900/60 p-4 border-l-4 border-cyan-400 backdrop-blur-md">
          <div className="text-xs text-cyan-500 uppercase tracking-widest font-bold">Commander Score</div>
          <div className="text-4xl font-orbitron text-white leading-none">{score.toLocaleString()}</div>
        </div>

        <div className="text-right">
          <div className="bg-slate-900/60 p-4 border-r-4 border-magenta-400 backdrop-blur-md">
            <div className="text-xs text-cyan-500 uppercase tracking-widest font-bold">Threat Level</div>
            <div className="text-4xl font-orbitron text-cyan-400 leading-none">{level}</div>
          </div>
        </div>
      </div>

      {/* Middle/Briefing Overlay */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full max-w-xl text-center">
         {!handActive && (
           <div className="bg-red-500/20 text-red-400 p-4 font-bold animate-pulse border border-red-500/50 backdrop-blur-sm">
             [ HAND NOT DETECTED: SHOW HANDS TO CAMERA ]
           </div>
         )}
      </div>

      {/* Bottom Bar */}
      <div className="flex justify-between items-end gap-8">
        <div className="flex-1 max-w-lg bg-slate-900/60 p-4 border-t-2 border-cyan-400/30 backdrop-blur-md">
          <div className="text-[10px] text-cyan-400/60 mb-1 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-cyan-400 animate-pulse"></span>
            TACTICAL AI BRIEFING
          </div>
          <p className="text-cyan-100 text-lg leading-tight italic">
            "{briefing}"
          </p>
        </div>

        <div className="w-64 bg-slate-900/60 p-4 border-t-2 border-red-500/30 backdrop-blur-md">
          <div className="text-xs text-red-400 uppercase font-bold mb-2">Hull Integrity</div>
          <div className="w-full h-4 bg-slate-800 rounded-full overflow-hidden border border-red-500/20">
            <div 
              className={`h-full transition-all duration-300 ${health > 30 ? 'bg-cyan-400' : 'bg-red-500'}`}
              style={{ width: `${health}%` }}
            ></div>
          </div>
          <div className="flex justify-between mt-1">
            <span className="text-[10px] text-red-400/60">SYS_CRITICAL</span>
            <span className="text-xs font-bold text-white">{health}%</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default HUD;

import React from 'react';

interface SplashScreenProps {
  onStart: () => void;
  isLoading: boolean;
  isGameOver: boolean;
  score: number;
}

const SplashScreen: React.FC<SplashScreenProps> = ({ onStart, isLoading, isGameOver, score }) => {
  return (
    <div className="absolute inset-0 z-50 flex items-center justify-center bg-slate-950 p-6 overflow-hidden">
      {/* Background Decorative Elements */}
      <div className="absolute inset-0 opacity-10 pointer-events-none">
        <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-cyan-900 via-transparent to-transparent"></div>
        <div className="grid grid-cols-12 gap-4 w-full h-full">
           {Array.from({length: 48}).map((_, i) => (
             <div key={i} className="border border-cyan-500/20 aspect-square"></div>
           ))}
        </div>
      </div>

      <div className="relative z-10 max-w-2xl w-full text-center space-y-8">
        <div>
          <h1 className="text-6xl md:text-8xl font-orbitron font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-400 via-white to-cyan-400 animate-pulse tracking-tighter">
            {isGameOver ? 'MISSION FAILED' : 'GEMINI STRIKE'}
          </h1>
          <div className="h-1 w-full bg-gradient-to-r from-transparent via-cyan-400 to-transparent mt-2"></div>
          <p className="mt-4 text-cyan-500 tracking-[0.4em] font-bold uppercase text-sm">
            Neural Interactive Tactical System
          </p>
        </div>

        {isGameOver && (
          <div className="bg-slate-900 border border-red-500/30 p-6 backdrop-blur-lg">
            <div className="text-sm text-red-400 uppercase tracking-widest">Final Operational Score</div>
            <div className="text-6xl font-orbitron text-white">{score.toLocaleString()}</div>
          </div>
        )}

        <div className="space-y-4 bg-slate-900/50 p-8 border border-cyan-500/20 backdrop-blur-xl rounded-sm">
          {!isGameOver && (
             <div className="text-left space-y-3 mb-8">
                <h3 className="text-cyan-400 font-bold flex items-center gap-2">
                   <span className="w-2 h-2 bg-cyan-400 rounded-full"></span>
                   NEURAL INTERFACE INSTRUCTIONS
                </h3>
                <ul className="text-cyan-100/70 text-sm space-y-2">
                   <li className="flex gap-2">
                      <span className="text-cyan-400">01.</span>
                      Enable Camera Access when prompted.
                   </li>
                   <li className="flex gap-2">
                      <span className="text-cyan-400">02.</span>
                      Position your hand so the sensor detects it.
                   </li>
                   <li className="flex gap-2">
                      <span className="text-cyan-400">03.</span>
                      <strong>INDEX FINGER:</strong> Use as target crosshair.
                   </li>
                   <li className="flex gap-2">
                      <span className="text-cyan-400">04.</span>
                      <strong>PINCH (Thumb + Index):</strong> Fire weapon system.
                   </li>
                </ul>
             </div>
          )}

          <button
            onClick={onStart}
            disabled={isLoading}
            className="w-full group relative overflow-hidden bg-cyan-500 hover:bg-cyan-400 text-slate-950 py-6 px-12 font-orbitron font-bold text-2xl transition-all duration-300 disabled:opacity-50"
          >
            <span className="relative z-10">
              {isLoading ? 'INITIALIZING LINK...' : (isGameOver ? 'REBOOT SYSTEM' : 'INITIALIZE LINK')}
            </span>
            <div className="absolute inset-0 w-full h-full bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-500 skew-x-12"></div>
          </button>

          <p className="text-cyan-500/50 text-[10px] uppercase tracking-widest pt-4">
            Secured Tactical Data Link v3.11 // AI Powered Briefing Active
          </p>
        </div>
      </div>
    </div>
  );
};

export default SplashScreen;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { GameState, Target, Particle, Vector2, MediaPipeLandmark } from '../types';
import { GAME_CONFIG, COLORS } from '../constants';

interface GameEngineProps {
  gameState: GameState;
  updateGameState: (updates: Partial<GameState>) => void;
  onGameOver: () => void;
}

const GameEngine: React.FC<GameEngineProps> = ({ gameState, updateGameState, onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const lastUpdateRef = useRef<number>(0);
  const lastSpawnRef = useRef<number>(0);
  const handsRef = useRef<any>(null);
  const smoothedHandPos = useRef<Vector2>({ x: 0.5, y: 0.5 });

  // Local state references for the game loop to avoid stale closure issues
  const targetsRef = useRef<Target[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const healthRef = useRef<number>(GAME_CONFIG.INITIAL_HEALTH);
  const scoreRef = useRef<number>(0);
  const isFiringRef = useRef<boolean>(false);
  const lastFiredRef = useRef<number>(0);
  const isMounted = useRef<boolean>(true);

  useEffect(() => {
    isMounted.current = true;
    return () => {
      isMounted.current = false;
    };
  }, []);

  // Initialize MediaPipe
  useEffect(() => {
    if (!videoRef.current) return;

    const { Hands, Camera } = (window as any);

    if (!Hands || !Camera) {
      console.error("MediaPipe Hands or Camera not loaded yet");
      return;
    }

    const hands = new Hands({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/hands/${file}`
    });

    hands.setOptions({
      maxNumHands: 1,
      modelComplexity: 1,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5
    });

    hands.onResults((results: any) => {
      if (!isMounted.current) return;
      if (results.multiHandLandmarks && results.multiHandLandmarks.length > 0) {
        const landmarks = results.multiHandLandmarks[0];

        // Use Index Finger Tip (8) for position
        const indexTip = landmarks[8];
        const thumbTip = landmarks[4];

        const targetX = 1 - indexTip.x;
        const targetY = indexTip.y;

        smoothedHandPos.current = {
          x: smoothedHandPos.current.x * GAME_CONFIG.HAND_SMOOTHING + targetX * (1 - GAME_CONFIG.HAND_SMOOTHING),
          y: smoothedHandPos.current.y * GAME_CONFIG.HAND_SMOOTHING + targetY * (1 - GAME_CONFIG.HAND_SMOOTHING)
        };

        const distance = Math.sqrt(
          Math.pow(indexTip.x - thumbTip.x, 2) + 
          Math.pow(indexTip.y - thumbTip.y, 2)
        );

        const isPinching = distance < 0.05;

        updateGameState({
          handActive: true,
          handPos: smoothedHandPos.current,
          isFiring: isPinching
        });
        isFiringRef.current = isPinching;

      } else {
        updateGameState({ handActive: false, isFiring: false });
        isFiringRef.current = false;
      }
    });

    const camera = new Camera(videoRef.current, {
      onFrame: async () => {
        if (isMounted.current && videoRef.current && videoRef.current.readyState >= 2) {
          await hands.send({ image: videoRef.current });
        }
      },
      width: 1280,
      height: 720
    });

    camera.start().catch((e: any) => console.error("Camera start failed", e));
    handsRef.current = hands;

    return () => {
      camera.stop();
      hands.close();
    };
  }, [updateGameState]);

  // Game loop
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let requestId: number;

    const animate = (time: number) => {
      if (!gameState.isPlaying || !isMounted.current || !canvas) return;

      const delta = lastUpdateRef.current ? time - lastUpdateRef.current : 0;
      lastUpdateRef.current = time;

      // 1. Spawning
      if (time - lastSpawnRef.current > (GAME_CONFIG.TARGET_SPAWN_RATE / (1 + (gameState.level - 1) * 0.2))) {
        const id = Math.random().toString(36).substr(2, 9);
        const type = Math.random() > 0.9 ? 'boss' : (Math.random() > 0.7 ? 'scout' : 'drone');
        const size = type === 'boss' ? 80 : (type === 'scout' ? 30 : 50);
        const health = type === 'boss' ? 5 : 1;

        targetsRef.current.push({
          id,
          pos: { x: Math.random() * (canvas.width - 100) + 50, y: -50 },
          vel: { x: (Math.random() - 0.5) * 2, y: GAME_CONFIG.TARGET_BASE_SPEED + Math.random() * gameState.level },
          size,
          health,
          maxHealth: health,
          type,
          color: type === 'boss' ? COLORS.MAGENTA : (type === 'scout' ? COLORS.YELLOW : COLORS.CYAN),
          points: type === 'boss' ? 500 : (type === 'scout' ? 200 : 100)
        });
        lastSpawnRef.current = time;
      }

      // 2. Firing Logic
      if (isFiringRef.current && time - lastFiredRef.current > GAME_CONFIG.FIRE_RATE) {
        lastFiredRef.current = time;
        const fireX = smoothedHandPos.current.x * canvas.width;
        const fireY = smoothedHandPos.current.y * canvas.height;

        targetsRef.current = targetsRef.current.filter(t => {
          const dx = fireX - t.pos.x;
          const dy = fireY - t.pos.y;
          const dist = Math.sqrt(dx*dx + dy*dy);

          if (dist < t.size) {
            t.health -= 1;
            for(let i=0; i<5; i++) {
              particlesRef.current.push({
                id: Math.random().toString(),
                pos: { x: fireX, y: fireY },
                vel: { x: (Math.random()-0.5)*10, y: (Math.random()-0.5)*10 },
                life: 1,
                maxLife: 1,
                color: t.color
              });
            }

            if (t.health <= 0) {
              scoreRef.current += t.points;
              if (scoreRef.current > gameState.level * 2000) {
                 updateGameState({ level: gameState.level + 1 });
              }
              for(let i=0; i<GAME_CONFIG.PARTICLE_COUNT; i++) {
                particlesRef.current.push({
                  id: Math.random().toString(),
                  pos: { ...t.pos },
                  vel: { x: (Math.random()-0.5)*15, y: (Math.random()-0.5)*15 },
                  life: 1,
                  maxLife: 1,
                  color: t.color
                });
              }
              return false;
            }
          }
          return true;
        });

        updateGameState({ score: scoreRef.current });
      }

      // 3. Movement & Collision
      targetsRef.current = targetsRef.current.filter(t => {
        t.pos.x += t.vel.x;
        t.pos.y += t.vel.y;

        if (t.pos.x < t.size || t.pos.x > canvas.width - t.size) t.vel.x *= -1;

        if (t.pos.y > canvas.height + t.size) {
          healthRef.current -= 10;
          updateGameState({ health: healthRef.current });
          if (healthRef.current <= 0) {
            onGameOver();
            return false;
          }
          return false;
        }
        return true;
      });

      // Particles
      particlesRef.current = particlesRef.current.filter(p => {
        p.pos.x += p.vel.x;
        p.pos.y += p.vel.y;
        p.life -= 0.02;
        return p.life > 0;
      });

      // 4. Rendering
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      targetsRef.current.forEach(t => {
        ctx.save();
        ctx.translate(t.pos.x, t.pos.y);
        ctx.shadowBlur = 15;
        ctx.shadowColor = t.color;
        ctx.strokeStyle = t.color;
        ctx.lineWidth = 3;

        if (t.type === 'drone') {
          ctx.strokeRect(-t.size/2, -t.size/2, t.size, t.size);
          ctx.beginPath();
          ctx.moveTo(-t.size/4, -t.size/4);
          ctx.lineTo(t.size/4, t.size/4);
          ctx.stroke();
        } else if (t.type === 'scout') {
          ctx.beginPath();
          ctx.moveTo(0, -t.size/2);
          ctx.lineTo(t.size/2, t.size/2);
          ctx.lineTo(-t.size/2, t.size/2);
          ctx.closePath();
          ctx.stroke();
        } else {
          ctx.strokeRect(-t.size/2, -t.size/2, t.size, t.size);
          ctx.strokeRect(-t.size/3, -t.size/3, t.size*0.6, t.size*0.6);
        }

        if (t.maxHealth > 1) {
          ctx.fillStyle = COLORS.RED;
          ctx.fillRect(-t.size/2, -t.size/2 - 10, t.size, 5);
          ctx.fillStyle = COLORS.GREEN;
          ctx.fillRect(-t.size/2, -t.size/2 - 10, t.size * (t.health/t.maxHealth), 5);
        }
        ctx.restore();
      });

      particlesRef.current.forEach(p => {
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.fillRect(p.pos.x, p.pos.y, 4, 4);
      });
      ctx.globalAlpha = 1.0;

      const hx = smoothedHandPos.current.x * canvas.width;
      const hy = smoothedHandPos.current.y * canvas.height;

      ctx.save();
      ctx.translate(hx, hy);
      ctx.strokeStyle = isFiringRef.current ? COLORS.RED : COLORS.CYAN;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.arc(0, 0, isFiringRef.current ? 15 : 25, 0, Math.PI * 2);
      ctx.stroke();

      ctx.beginPath();
      ctx.moveTo(-35, 0); ctx.lineTo(-15, 0);
      ctx.moveTo(35, 0); ctx.lineTo(15, 0);
      ctx.moveTo(0, -35); ctx.lineTo(0, -15);
      ctx.moveTo(0, 35); ctx.lineTo(0, 15);
      ctx.stroke();

      if (isFiringRef.current) {
        ctx.fillStyle = COLORS.RED;
        ctx.beginPath();
        ctx.arc(0, 0, 5, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.restore();

      requestId = requestAnimationFrame(animate);
    };

    requestId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(requestId);
  }, [gameState.isPlaying, gameState.level, onGameOver, updateGameState]);

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      <video
        ref={videoRef}
        className="hidden"
        playsInline
        muted
      />

      <video
        className="absolute inset-0 w-full h-full object-cover scale-x-[-1] opacity-40 blur-sm brightness-50"
        autoPlay
        playsInline
        muted
        ref={(el) => {
           if (el && videoRef.current && videoRef.current.srcObject) {
             el.srcObject = videoRef.current.srcObject;
           }
        }}
      />

      <canvas
        ref={canvasRef}
        width={1280}
        height={720}
        className="relative w-full h-full object-contain"
      />
    </div>
  );
};

export default GameEngine;

export interface Vector2 {
  x: number;
  y: number;
}

export interface Target {
  id: string;
  pos: Vector2;
  vel: Vector2;
  size: number;
  health: number;
  maxHealth: number;
  type: 'drone' | 'scout' | 'boss';
  color: string;
  points: number;
  hitTimer: number; // For flashing when hit
}

export interface Particle {
  id: string;
  pos: Vector2;
  vel: Vector2;
  life: number;
  maxLife: number;
  color: string;
  size: number;
}

export interface GameState {
  score: number;
  health: number;
  level: number;
  isGameOver: boolean;
  isPlaying: boolean;
  targets: Target[];
  particles: Particle[];
  handActive: boolean;
  handPos: Vector2;
  isFiring: boolean;
  lastFired: number;
  briefing: string;
}

export interface MediaPipeLandmark {
  x: number;
  y: number;
  z: number;
}

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { GameState, Target, Particle, Vector2, MediaPipeLandmark } from '../types';
import { GAME_CONFIG, COLORS } from '../constants';

interface GameEngineProps {
  gameState: GameState;
  updateGameState: (updates: Partial<GameState>) => void;
  onGameOver: () => void;
}

const GameEngine: React.FC<GameEngineProps> = ({ gameState, updateGameState, onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const lastUpdateRef = useRef<number>(0);
  const lastSpawnRef = useRef<number>(0);
  const handsRef = useRef<any>(null);
  const smoothedHandPos = useRef<Vector2>({ x: 0.5, y: 0.5 });

  // Local state references
  const targetsRef = useRef<Target[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const healthRef = useRef<number>(GAME_CONFIG.INITIAL_HEALTH);
  const scoreRef = useRef<number>(0);
  const isFiringRef = useRef<boolean>(false);
  const lastFiredRef = useRef<number>(0);
  const isMounted = useRef<boolean>(true);
  const damageFlashRef = useRef<number>(0); // 0 to 1 intensity
  const levelUpRef = useRef<number>(0); // countdown for level up display

  useEffect(() => {
    isMounted.current = true;
    return () => {
      isMounted.current = false;
    };
  }, []);

  // Initialize MediaPipe
  useEffect(() => {
    if (!videoRef.current) return;

    const { Hands, Camera } = (window as any);

    if (!Hands || !Camera) {
      console.error("MediaPipe Hands or Camera not loaded yet");
      return;
    }

    const hands = new Hands({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/hands/${file}`
    });

    hands.setOptions({
      maxNumHands: 1,
      modelComplexity: 1,
      minDetectionConfidence: 0.5,
      minTrackingConfidence: 0.5
    });

    hands.onResults((results: any) => {
      if (!isMounted.current) return;
      if (results.multiHandLandmarks && results.multiHandLandmarks.length > 0) {
        const landmarks = results.multiHandLandmarks[0];
        const indexTip = landmarks[8];
        const thumbTip = landmarks[4];

        const targetX = 1 - indexTip.x;
        const targetY = indexTip.y;

        smoothedHandPos.current = {
          x: smoothedHandPos.current.x * GAME_CONFIG.HAND_SMOOTHING + targetX * (1 - GAME_CONFIG.HAND_SMOOTHING),
          y: smoothedHandPos.current.y * GAME_CONFIG.HAND_SMOOTHING + targetY * (1 - GAME_CONFIG.HAND_SMOOTHING)
        };

        const distance = Math.sqrt(
          Math.pow(indexTip.x - thumbTip.x, 2) + 
          Math.pow(indexTip.y - thumbTip.y, 2)
        );

        const isPinching = distance < 0.05;

        updateGameState({
          handActive: true,
          handPos: smoothedHandPos.current,
          isFiring: isPinching
        });
        isFiringRef.current = isPinching;

      } else {
        updateGameState({ handActive: false, isFiring: false });
        isFiringRef.current = false;
      }
    });

    const camera = new Camera(videoRef.current, {
      onFrame: async () => {
        if (isMounted.current && videoRef.current && videoRef.current.readyState >= 2) {
          await hands.send({ image: videoRef.current });
        }
      },
      width: 1280,
      height: 720
    });

    camera.start().catch((e: any) => console.error("Camera start failed", e));
    handsRef.current = hands;

    return () => {
      camera.stop();
      hands.close();
    };
  }, [updateGameState]);

  // Game loop
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let requestId: number;

    const animate = (time: number) => {
      if (!gameState.isPlaying || !isMounted.current || !canvas) return;

      const delta = lastUpdateRef.current ? time - lastUpdateRef.current : 0;
      lastUpdateRef.current = time;

      // 1. Spawning
      const spawnInterval = GAME_CONFIG.TARGET_SPAWN_RATE / (1 + (gameState.level - 1) * 0.2);
      if (time - lastSpawnRef.current > spawnInterval) {
        const id = Math.random().toString(36).substr(2, 9);
        const type = Math.random() > 0.9 ? 'boss' : (Math.random() > 0.7 ? 'scout' : 'drone');
        const size = type === 'boss' ? 80 : (type === 'scout' ? 30 : 50);
        const health = type === 'boss' ? 5 : 1;

        targetsRef.current.push({
          id,
          pos: { x: Math.random() * (canvas.width - 100) + 50, y: -50 },
          vel: { x: (Math.random() - 0.5) * 2, y: GAME_CONFIG.TARGET_BASE_SPEED + Math.random() * (gameState.level * 0.5) },
          size,
          health,
          maxHealth: health,
          type,
          color: type === 'boss' ? COLORS.MAGENTA : (type === 'scout' ? COLORS.YELLOW : COLORS.CYAN),
          points: type === 'boss' ? 500 : (type === 'scout' ? 200 : 100),
          hitTimer: 0
        });
        lastSpawnRef.current = time;
      }

      // 2. Firing Logic
      if (isFiringRef.current && time - lastFiredRef.current > GAME_CONFIG.FIRE_RATE) {
        lastFiredRef.current = time;
        const fireX = smoothedHandPos.current.x * canvas.width;
        const fireY = smoothedHandPos.current.y * canvas.height;

        targetsRef.current.forEach(t => {
          const dx = fireX - t.pos.x;
          const dy = fireY - t.pos.y;
          const dist = Math.sqrt(dx*dx + dy*dy);

          if (dist < t.size) {
            t.health -= 1;
            t.hitTimer = 10; // flash for 10 frames

            // Impact debris
            for(let i=0; i<8; i++) {
              particlesRef.current.push({
                id: Math.random().toString(),
                pos: { x: fireX, y: fireY },
                vel: { x: (Math.random()-0.5)*12, y: (Math.random()-0.5)*12 },
                life: 1,
                maxLife: 1,
                color: '#ffffff',
                size: Math.random() * 3 + 1
              });
            }
          }
        });

        // Check for kills and update score
        const killed = targetsRef.current.filter(t => t.health <= 0);
        if (killed.length > 0) {
          killed.forEach(t => {
            scoreRef.current += t.points;
            if (scoreRef.current > gameState.level * 2000) {
               updateGameState({ level: gameState.level + 1 });
               levelUpRef.current = 60; // display level up for 60 frames
            }
            // Large death explosion
            for(let i=0; i<GAME_CONFIG.PARTICLE_COUNT * 2; i++) {
              particlesRef.current.push({
                id: Math.random().toString(),
                pos: { ...t.pos },
                vel: { x: (Math.random()-0.5)*20, y: (Math.random()-0.5)*20 },
                life: 1,
                maxLife: 1.5,
                color: t.color,
                size: Math.random() * 6 + 2
              });
            }
          });
          targetsRef.current = targetsRef.current.filter(t => t.health > 0);
          updateGameState({ score: scoreRef.current });
        }
      }

      // 3. Movement & Collision
      targetsRef.current = targetsRef.current.filter(t => {
        t.pos.x += t.vel.x;
        t.pos.y += t.vel.y;
        if (t.hitTimer > 0) t.hitTimer--;

        if (t.pos.x < t.size || t.pos.x > canvas.width - t.size) t.vel.x *= -1;

        if (t.pos.y > canvas.height + t.size) {
          healthRef.current -= 10;
          damageFlashRef.current = 1.0;
          updateGameState({ health: healthRef.current });
          if (healthRef.current <= 0) {
            onGameOver();
            return false;
          }
          return false;
        }
        return true;
      });

      // Particles
      particlesRef.current = particlesRef.current.filter(p => {
        p.pos.x += p.vel.x;
        p.pos.y += p.vel.y;
        p.vel.x *= 0.98; // Friction
        p.vel.y *= 0.98;
        p.life -= 0.02;
        return p.life > 0;
      });

      // Update transient visual states
      if (damageFlashRef.current > 0) damageFlashRef.current -= 0.05;
      if (levelUpRef.current > 0) levelUpRef.current--;

      // 4. Rendering
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Render Targets
      targetsRef.current.forEach(t => {
        ctx.save();
        ctx.translate(t.pos.x, t.pos.y);

        const isHit = t.hitTimer > 0;
        ctx.shadowBlur = isHit ? 30 : 15;
        ctx.shadowColor = isHit ? '#ffffff' : t.color;
        ctx.strokeStyle = isHit ? '#ffffff' : t.color;
        ctx.lineWidth = isHit ? 6 : 3;

        if (t.type === 'drone') {
          ctx.strokeRect(-t.size/2, -t.size/2, t.size, t.size);
          ctx.beginPath();
          ctx.moveTo(-t.size/4, -t.size/4);
          ctx.lineTo(t.size/4, t.size/4);
          ctx.stroke();
        } else if (t.type === 'scout') {
          ctx.beginPath();
          ctx.moveTo(0, -t.size/2);
          ctx.lineTo(t.size/2, t.size/2);
          ctx.lineTo(-t.size/2, t.size/2);
          ctx.closePath();
          ctx.stroke();
        } else {
          ctx.strokeRect(-t.size/2, -t.size/2, t.size, t.size);
          ctx.strokeRect(-t.size/3, -t.size/3, t.size*0.6, t.size*0.6);
        }

        if (t.maxHealth > 1) {
          ctx.fillStyle = COLORS.RED;
          ctx.fillRect(-t.size/2, -t.size/2 - 15, t.size, 6);
          ctx.fillStyle = COLORS.GREEN;
          ctx.fillRect(-t.size/2, -t.size/2 - 15, t.size * (t.health/t.maxHealth), 6);
        }
        ctx.restore();
      });

      // Render Particles
      particlesRef.current.forEach(p => {
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.fillRect(p.pos.x, p.pos.y, p.size, p.size);
      });
      ctx.globalAlpha = 1.0;

      // Crosshair and Muzzle Flash
      const hx = smoothedHandPos.current.x * canvas.width;
      const hy = smoothedHandPos.current.y * canvas.height;
      const muzzleFlashActive = (time - lastFiredRef.current < 50) && isFiringRef.current;

      ctx.save();
      ctx.translate(hx, hy);

      if (muzzleFlashActive) {
        const gradient = ctx.createRadialGradient(0, 0, 0, 0, 0, 60);
        gradient.addColorStop(0, 'rgba(255, 255, 255, 0.8)');
        gradient.addColorStop(0.2, 'rgba(255, 0, 0, 0.6)');
        gradient.addColorStop(1, 'rgba(255, 0, 0, 0)');
        ctx.fillStyle = gradient;
        ctx.beginPath();
        ctx.arc(0, 0, 60, 0, Math.PI * 2);
        ctx.fill();

        // Lens flare lines
        ctx.strokeStyle = 'rgba(255, 255, 255, 0.4)';
        ctx.lineWidth = 1;
        for(let i=0; i<4; i++) {
          ctx.rotate(Math.PI / 2);
          ctx.beginPath();
          ctx.moveTo(0, 0);
          ctx.lineTo(0, 150);
          ctx.stroke();
        }
      }

      ctx.strokeStyle = isFiringRef.current ? COLORS.RED : COLORS.CYAN;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.arc(0, 0, isFiringRef.current ? 15 : 25, 0, Math.PI * 2);
      ctx.stroke();

      // Crosshair lines
      ctx.beginPath();
      ctx.moveTo(-35, 0); ctx.lineTo(-15, 0);
      ctx.moveTo(35, 0); ctx.lineTo(15, 0);
      ctx.moveTo(0, -35); ctx.lineTo(0, -15);
      ctx.moveTo(0, 35); ctx.lineTo(0, 15);
      ctx.stroke();

      if (isFiringRef.current) {
        ctx.fillStyle = COLORS.RED;
        ctx.beginPath();
        ctx.arc(0, 0, 5, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.restore();

      // Damage Vignette
      if (damageFlashRef.current > 0) {
        const grad = ctx.createRadialGradient(canvas.width/2, canvas.height/2, canvas.height/3, canvas.width/2, canvas.height/2, canvas.width/1.2);
        grad.addColorStop(0, 'transparent');
        grad.addColorStop(1, `rgba(255, 0, 0, ${damageFlashRef.current * 0.5})`);
        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }

      // Level Up Text
      if (levelUpRef.current > 0) {
        ctx.save();
        ctx.font = 'bold 80px Orbitron';
        ctx.textAlign = 'center';
        ctx.fillStyle = `rgba(34, 211, 238, ${levelUpRef.current / 60})`;
        ctx.shadowBlur = 20;
        ctx.shadowColor = '#22d3ee';
        ctx.fillText(`LEVEL ${gameState.level} ACTIVE`, canvas.width/2, canvas.height/2);
        ctx.restore();
      }

      requestId = requestAnimationFrame(animate);
    };

    requestId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(requestId);
  }, [gameState.isPlaying, gameState.level, onGameOver, updateGameState]);

  return (
    <div className="relative w-full h-full flex items-center justify-center">
      <video
        ref={videoRef}
        className="hidden"
        playsInline
        muted
      />

      <video
        className="absolute inset-0 w-full h-full object-cover scale-x-[-1] opacity-40 blur-sm brightness-50"
        autoPlay
        playsInline
        muted
        ref={(el) => {
           if (el && videoRef.current && videoRef.current.srcObject) {
             el.srcObject = videoRef.current.srcObject;
           }
        }}
      />

      <canvas
        ref={canvasRef}
        width={1280}
        height={720}
        className="relative w-full h-full object-contain"
      />
    </div>
  );
};

export default GameEngine;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { GameState, Target, Particle, Vector2, MediaPipeLandmark } from '../types';
import { GAME_CONFIG, COLORS } from '../constants';

interface GameEngineProps {
  gameState: GameState;
  updateGameState: (updates: Partial<GameState>) => void;
  onGameOver: () => void;
}

const GameEngine: React.FC<GameEngineProps> = ({ gameState, updateGameState, onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const lastUpdateRef = useRef<number>(0);
  const lastSpawnRef = useRef<number>(0);
  const handsRef = useRef<any>(null);
  const smoothedHandPos = useRef<Vector2>({ x: 0.5, y: 0.5 });
  const handLandmarksRef = useRef<any[]>([]);

  // Local state references
  const targetsRef = useRef<Target[]>([]);
  const particlesRef = useRef<Particle[]>([]);
  const healthRef = useRef<number>(GAME_CONFIG.INITIAL_HEALTH);
  const scoreRef = useRef<number>(0);
  const isFiringRef = useRef<boolean>(false);
  const lastFiredRef = useRef<number>(0);
  const isMounted = useRef<boolean>(true);
  const damageFlashRef = useRef<number>(0);
  const levelUpRef = useRef<number>(0);

  useEffect(() => {
    isMounted.current = true;
    return () => {
      isMounted.current = false;
    };
  }, []);

  // Initialize MediaPipe
  useEffect(() => {
    if (!videoRef.current) return;

    const { Hands, Camera } = (window as any);

    if (!Hands || !Camera) {
      console.error("MediaPipe Hands or Camera not loaded yet");
      return;
    }

    const hands = new Hands({
      locateFile: (file: string) => `https://cdn.jsdelivr.net/npm/@mediapipe/hands/${file}`
    });

    hands.setOptions({
      maxNumHands: 1,
      modelComplexity: 1, // 0 for Lite, 1 for Full. Full is better for accuracy.
      minDetectionConfidence: 0.6,
      minTrackingConfidence: 0.6
    });

    hands.onResults((results: any) => {
      if (!isMounted.current) return;

      if (results.multiHandLandmarks && results.multiHandLandmarks.length > 0) {
        const landmarks = results.multiHandLandmarks[0];
        handLandmarksRef.current = landmarks;

        // Use Index Finger Tip (8) for position
        const indexTip = landmarks[8];
        const thumbTip = landmarks[4];

        // Mirror the X coordinate for natural interaction
        const targetX = 1 - indexTip.x;
        const targetY = indexTip.y;

        // Dynamic smoothing: slow down smoothing when movement is small to reduce jitter, 
        // speed up when movement is large for responsiveness.
        const smoothing = GAME_CONFIG.HAND_SMOOTHING;
        smoothedHandPos.current = {
          x: smoothedHandPos.current.x * smoothing + targetX * (1 - smoothing),
          y: smoothedHandPos.current.y * smoothing + targetY * (1 - smoothing)
        };

        // Improved Pinch detection (distance between thumb and index finger tip)
        const dx = indexTip.x - thumbTip.x;
        const dy = indexTip.y - thumbTip.y;
        const dz = indexTip.z - thumbTip.z;
        const distance = Math.sqrt(dx*dx + dy*dy + dz*dz);

        const isPinching = distance < 0.06;

        updateGameState({
          handActive: true,
          handPos: smoothedHandPos.current,
          isFiring: isPinching
        });
        isFiringRef.current = isPinching;
      } else {
        handLandmarksRef.current = [];
        updateGameState({ handActive: false, isFiring: false });
        isFiringRef.current = false;
      }
    });

    const camera = new Camera(videoRef.current, {
      onFrame: async () => {
        if (isMounted.current && videoRef.current && videoRef.current.readyState >= 2) {
          await hands.send({ image: videoRef.current });
        }
      },
      width: 1280,
      height: 720
    });

    camera.start().catch((e: any) => console.error("Camera start failed", e));
    handsRef.current = hands;

    return () => {
      camera.stop();
      hands.close();
    };
  }, [updateGameState]);

  // Game loop
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let requestId: number;

    const animate = (time: number) => {
      if (!gameState.isPlaying || !isMounted.current || !canvas) return;

      const delta = lastUpdateRef.current ? time - lastUpdateRef.current : 0;
      lastUpdateRef.current = time;

      // 1. Spawning logic
      const spawnInterval = GAME_CONFIG.TARGET_SPAWN_RATE / (1 + (gameState.level - 1) * 0.2);
      if (time - lastSpawnRef.current > spawnInterval) {
        const id = Math.random().toString(36).substr(2, 9);
        const type = Math.random() > 0.9 ? 'boss' : (Math.random() > 0.7 ? 'scout' : 'drone');
        const size = type === 'boss' ? 80 : (type === 'scout' ? 30 : 50);
        const health = type === 'boss' ? 5 : 1;

        targetsRef.current.push({
          id,
          pos: { x: Math.random() * (canvas.width - 100) + 50, y: -50 },
          vel: { x: (Math.random() - 0.5) * 2, y: GAME_CONFIG.TARGET_BASE_SPEED + Math.random() * (gameState.level * 0.5) },
          size,
          health,
          maxHealth: health,
          type,
          color: type === 'boss' ? COLORS.MAGENTA : (type === 'scout' ? COLORS.YELLOW : COLORS.CYAN),
          points: type === 'boss' ? 500 : (type === 'scout' ? 200 : 100),
          hitTimer: 0
        });
        lastSpawnRef.current = time;
      }

      // 2. Firing Logic
      if (isFiringRef.current && time - lastFiredRef.current > GAME_CONFIG.FIRE_RATE) {
        lastFiredRef.current = time;
        const fireX = smoothedHandPos.current.x * canvas.width;
        const fireY = smoothedHandPos.current.y * canvas.height;

        targetsRef.current.forEach(t => {
          const dx = fireX - t.pos.x;
          const dy = fireY - t.pos.y;
          const dist = Math.sqrt(dx*dx + dy*dy);

          if (dist < t.size) {
            t.health -= 1;
            t.hitTimer = 10;
            for(let i=0; i<8; i++) {
              particlesRef.current.push({
                id: Math.random().toString(),
                pos: { x: fireX, y: fireY },
                vel: { x: (Math.random()-0.5)*12, y: (Math.random()-0.5)*12 },
                life: 1,
                maxLife: 1,
                color: '#ffffff',
                size: Math.random() * 3 + 1
              });
            }
          }
        });

        const killed = targetsRef.current.filter(t => t.health <= 0);
        if (killed.length > 0) {
          killed.forEach(t => {
            scoreRef.current += t.points;
            if (scoreRef.current > gameState.level * 2000) {
               updateGameState({ level: gameState.level + 1 });
               levelUpRef.current = 60;
            }
            for(let i=0; i<GAME_CONFIG.PARTICLE_COUNT * 2; i++) {
              particlesRef.current.push({
                id: Math.random().toString(),
                pos: { ...t.pos },
                vel: { x: (Math.random()-0.5)*20, y: (Math.random()-0.5)*20 },
                life: 1,
                maxLife: 1.5,
                color: t.color,
                size: Math.random() * 6 + 2
              });
            }
          });
          targetsRef.current = targetsRef.current.filter(t => t.health > 0);
          updateGameState({ score: scoreRef.current });
        }
      }

      // 3. Movement & Collision
      targetsRef.current = targetsRef.current.filter(t => {
        t.pos.x += t.vel.x;
        t.pos.y += t.vel.y;
        if (t.hitTimer > 0) t.hitTimer--;

        if (t.pos.x < t.size || t.pos.x > canvas.width - t.size) t.vel.x *= -1;

        if (t.pos.y > canvas.height + t.size) {
          healthRef.current -= 10;
          damageFlashRef.current = 1.0;
          updateGameState({ health: healthRef.current });
          if (healthRef.current <= 0) {
            onGameOver();
            return false;
          }
          return false;
        }
        return true;
      });

      particlesRef.current = particlesRef.current.filter(p => {
        p.pos.x += p.vel.x;
        p.pos.y += p.vel.y;
        p.vel.x *= 0.98;
        p.vel.y *= 0.98;
        p.life -= 0.02;
        return p.life > 0;
      });

      if (damageFlashRef.current > 0) damageFlashRef.current -= 0.05;
      if (levelUpRef.current > 0) levelUpRef.current--;

      // 4. Rendering
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Rendering: Hand Skeleton (Cyberpunk Style)
      if (handLandmarksRef.current.length > 0) {
        ctx.save();
        ctx.lineWidth = 2;
        ctx.shadowBlur = 10;
        ctx.shadowColor = COLORS.CYAN;
        ctx.strokeStyle = "rgba(34, 211, 238, 0.4)";

        const HAND_CONNECTIONS = (window as any).HAND_CONNECTIONS || [
          [0, 1], [1, 2], [2, 3], [3, 4], // thumb
          [0, 5], [5, 6], [6, 7], [7, 8], // index
          [0, 9], [9, 10], [10, 11], [11, 12], // middle
          [0, 13], [13, 14], [14, 15], [15, 16], // ring
          [0, 17], [17, 18], [18, 19], [19, 20], // pinky
          [5, 9], [9, 13], [13, 17] // palm
        ];

        HAND_CONNECTIONS.forEach(([startIdx, endIdx]: [number, number]) => {
          const start = handLandmarksRef.current[startIdx];
          const end = handLandmarksRef.current[endIdx];
          if (start && end) {
            ctx.beginPath();
            ctx.moveTo((1 - start.x) * canvas.width, start.y * canvas.height);
            ctx.lineTo((1 - end.x) * canvas.width, end.y * canvas.height);
            ctx.stroke();
          }
        });

        // Joints
        ctx.fillStyle = COLORS.CYAN;
        handLandmarksRef.current.forEach((lm) => {
          ctx.beginPath();
          ctx.arc((1 - lm.x) * canvas.width, lm.y * canvas.height, 3, 0, Math.PI * 2);
          ctx.fill();
        });
        ctx.restore();
      }

      // Render Targets
      targetsRef.current.forEach(t => {
        ctx.save();
        ctx.translate(t.pos.x, t.pos.y);
        const isHit = t.hitTimer > 0;
        ctx.shadowBlur = isHit ? 30 : 15;
        ctx.shadowColor = isHit ? '#ffffff' : t.color;
        ctx.strokeStyle = isHit ? '#ffffff' : t.color;
        ctx.lineWidth = isHit ? 6 : 3;

        if (t.type === 'drone') {
          ctx.strokeRect(-t.size/2, -t.size/2, t.size, t.size);
          ctx.beginPath(); ctx.moveTo(-t.size/4, -t.size/4); ctx.lineTo(t.size/4, t.size/4); ctx.stroke();
        } else if (t.type === 'scout') {
          ctx.beginPath(); ctx.moveTo(0, -t.size/2); ctx.lineTo(t.size/2, t.size/2); ctx.lineTo(-t.size/2, t.size/2); ctx.closePath(); ctx.stroke();
        } else {
          ctx.strokeRect(-t.size/2, -t.size/2, t.size, t.size);
          ctx.strokeRect(-t.size/3, -t.size/3, t.size*0.6, t.size*0.6);
        }

        if (t.maxHealth > 1) {
          ctx.fillStyle = COLORS.RED;
          ctx.fillRect(-t.size/2, -t.size/2 - 15, t.size, 6);
          ctx.fillStyle = COLORS.GREEN;
          ctx.fillRect(-t.size/2, -t.size/2 - 15, t.size * (t.health/t.maxHealth), 6);
        }
        ctx.restore();
      });

      // Particles
      particlesRef.current.forEach(p => {
        ctx.globalAlpha = p.life;
        ctx.fillStyle = p.color;
        ctx.fillRect(p.pos.x, p.pos.y, p.size, p.size);
      });
      ctx.globalAlpha = 1.0;

      // Crosshair and Effects
      const hx = smoothedHandPos.current.x * canvas.width;
      const hy = smoothedHandPos.current.y * canvas.height;
      const muzzleFlashActive = (time - lastFiredRef.current < 50) && isFiringRef.current;

      ctx.save();
      ctx.translate(hx, hy);

      if (muzzleFlashActive) {
        const gradient = ctx.createRadialGradient(0, 0, 0, 0, 0, 80);
        gradient.addColorStop(0, 'white');
        gradient.addColorStop(0.3, 'rgba(255, 0, 0, 0.8)');
        gradient.addColorStop(1, 'transparent');
        ctx.fillStyle = gradient;
        ctx.beginPath(); ctx.arc(0, 0, 80, 0, Math.PI * 2); ctx.fill();

        ctx.strokeStyle = 'rgba(255, 255, 255, 0.5)';
        ctx.lineWidth = 1;
        for(let i=0; i<4; i++) {
          ctx.rotate(Math.PI / 2);
          ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(0, 200); ctx.stroke();
        }
      }

      ctx.strokeStyle = isFiringRef.current ? COLORS.RED : COLORS.CYAN;
      ctx.lineWidth = 2;
      ctx.shadowBlur = 10;
      ctx.shadowColor = ctx.strokeStyle;
      ctx.beginPath(); ctx.arc(0, 0, isFiringRef.current ? 15 : 25, 0, Math.PI * 2); ctx.stroke();

      ctx.beginPath();
      ctx.moveTo(-35, 0); ctx.lineTo(-15, 0);
      ctx.moveTo(35, 0); ctx.lineTo(15, 0);
      ctx.moveTo(0, -35); ctx.lineTo(0, -15);
      ctx.moveTo(0, 35); ctx.lineTo(0, 15);
      ctx.stroke();

      if (isFiringRef.current) {
        ctx.fillStyle = COLORS.RED;
        ctx.beginPath(); ctx.arc(0, 0, 5, 0, Math.PI * 2); ctx.fill();
      }
      ctx.restore();

      // Overlays
      if (damageFlashRef.current > 0) {
        const grad = ctx.createRadialGradient(canvas.width/2, canvas.height/2, canvas.height/3, canvas.width/2, canvas.height/2, canvas.width/1.1);
        grad.addColorStop(0, 'transparent');
        grad.addColorStop(1, `rgba(255, 0, 0, ${damageFlashRef.current * 0.4})`);
        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, canvas.width, canvas.height);
      }

      if (levelUpRef.current > 0) {
        ctx.save();
        ctx.font = 'bold 100px Orbitron';
        ctx.textAlign = 'center';
        ctx.fillStyle = `rgba(255, 255, 255, ${levelUpRef.current / 60})`;
        ctx.shadowBlur = 20;
        ctx.shadowColor = COLORS.CYAN;
        ctx.fillText(`THREAT LEVEL ${gameState.level}`, canvas.width/2, canvas.height/2);
        ctx.restore();
      }

      requestId = requestAnimationFrame(animate);
    };

    requestId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(requestId);
  }, [gameState.isPlaying, gameState.level, onGameOver, updateGameState]);

  return (
    <div className="relative w-full h-full flex items-center justify-center bg-black">
      <video ref={videoRef} className="hidden" playsInline muted />

      {/* Background Camera Feed with Cyberpunk post-processing */}
      <div className="absolute inset-0 w-full h-full overflow-hidden">
        <video
          className="w-full h-full object-cover scale-x-[-1] opacity-50 grayscale brightness-[0.7] contrast-125"
          autoPlay
          playsInline
          muted
          ref={(el) => {
            if (el && videoRef.current && videoRef.current.srcObject) {
              el.srcObject = videoRef.current.srcObject;
            }
          }}
        />
        {/* Digital noise overlay */}
        <div className="absolute inset-0 pointer-events-none opacity-[0.03] bg-[url('https://grainy-gradients.vercel.app/noise.svg')]"></div>
        {/* Subtle cyan vignette */}
        <div className="absolute inset-0 pointer-events-none bg-[radial-gradient(circle_at_center,_transparent_40%,_rgba(34,211,238,0.1)_100%)]"></div>
      </div>

      <canvas
        ref={canvasRef}
        width={1280}
        height={720}
        className="relative w-full h-full object-contain z-10"
      />
    </div>
  );
};

export default GameEngine;
